var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스, 저기 오십니다.","JPN":"リコリス、あちらにいらっしゃいます。","ENG":"Lycoris, there they come.","TWN":"莉克麗絲，他們來了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 자네들은…….","JPN":"おお、君たちは……","ENG":"Oh, you’re...","TWN":"喔，你們是……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"플로라 메이드 서비스의 메이드들이군요.","JPN":"フローラメイドサービスのメイドさんですね。","ENG":"The maids from the Flora Maid Service.","TWN":"芙蘿拉女僕服務公司的女僕們。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그렇습니다. 이렇게 만나뵙게 되어 영광입니다. 주인님.","JPN":"はい。お会いできて光栄です。ご主人様。","ENG":"Yes. We’re very honored to see you, Master.","TWN":"是的，主人，很榮幸見到您。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"저는 릴리. 그리고 이쪽은…….","JPN":"私はリリー、そしてこちらは……","ENG":"I’m Lily, and this is...","TWN":"我是莉莉，這位是…"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스야. 부르고 싶은 대로 불러.","JPN":"リコリスよ。適当に呼んで。","ENG":"Lycoris. Or just call me whatever you’d like.","TWN":"我是莉克麗絲，你想怎麼叫我都可以。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"딱히 나도 낯간지럽게 주인님이라고 부를 생각은 없으니까.","JPN":"別に私だってご主人様と呼びたいわけじゃないから。","ENG":"I’m not calling you Master, it’s embarrassing.","TWN":"反正我也不想噁心地稱呼你主人。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하, 괜찮네. 깡통이라고 불렀던 직원들도 있는 마당에.","JPN":"ははは、いいんだ。ボロ缶と呼んでいる社員もいるしな。","ENG":"Hah hah, I don’t mind. Some of my employees even call me a tin can, you know.","TWN":"哈哈，沒關係，有些員工還會叫我罐頭呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런데 여긴 어쩐 일인가? 모네 양이 걱정돼서?","JPN":"ところで、ここには何の用かね？　モネが心配だったのか？","ENG":"But why are you here? Were you worried about Mone?","TWN":"不過，你們來這裡有什麼事嗎？是因為擔心莫妮？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"누, 누가 누굴 걱정해?","JPN":"だ、誰が誰を心配するっていうの？","ENG":"W-worried? No one’s worried about anything!","TWN":"才…才不是咧！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그게……! 그냥 괜히 사고치면 골치 아파지니까 그렇지!","JPN":"……そう！　ただ余計な事故でも起こしたらまずいから監視にきただけ！","ENG":"I’m just... Well, we’re only here because it’s on us if Mone gets into trouble!","TWN":"我…我們是怕他闖禍給我們惹麻煩！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"모네는 메이드로서 아직 부족합니다.","JPN":"モネはメイドとしてまだ未熟です。","ENG":"Mone is still a trainee.","TWN":"莫妮還不是那麼成熟的女僕。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"평소에도 몸가짐을 바르게 하는지 늘 지켜 봐야죠.","JPN":"普段から身だしなみをちゃんとしているのか、常に見守らなければなりません。","ENG":"We’re here to check if Mone is acting accordingly as a maid.","TWN":"我們必須幫他注意平時的言行舉止。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"뭐……. 가급적이면 나서고 싶지는 않았지만.","JPN":"まあ……なるべく表には出たくはなかったけど。","ENG":"Although... we didn’t really want to be seen.","TWN":"嗯…可以的話，我是不太想這樣啦。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응? 어째서인가?","JPN":"うん？　どうして？","ENG":"Hm? Why not?","TWN":"嗯？為什麼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"혹시 혼자 먼 길을 온 모네 양에게 상처를 주고 싶지 않아서?!","JPN":"もしかしてモネを傷つけたくないからか？","ENG":"You didn’t want to hurt Mone’s feelings?","TWN":"你是怕大老遠回來的莫妮，知道後心裡會受傷嗎？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"역시 선배님! 요리 솜씨만 빼면 상냥하시지 말임다!","JPN":"さすが先輩！　料理の腕前以外は、本当に優しいっすね！","ENG":"I knew it, ma’am! You’re so nice, except for making spicy food!","TWN":"哇！前輩人好好！只是廚藝要再加油！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L32_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"너, 넌 왜 따라왔어?! 그런 거 아니라니까!","JPN":"あ、あんたなんでここにいるの！？　違うわよ！","ENG":"W-why are you here? I’m not that nice!","TWN":"你不要亂接話！我的意思不是那樣！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스. 주인님 앞입니다. 언성을 낮추세요.","JPN":"リコリス。ご主人様の前です。大声は控えてください。","ENG":"Lycoris, the Master is here. Lower your voice.","TWN":"莉克麗絲，在主人面前，請注意你的音量。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"앞으로 여기 머무시는 동안에는 저희가 모시겠습니다.","JPN":"これからここで滞在する間、私たちがお仕えします。","ENG":"We’ll be serving you while you’re staying here.","TWN":"主人在這裡的這段時間，就由我們來服侍您。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"우선은 안전한 곳으로 자리를 옮기시죠. 준비해 둔 안전 가옥으로 안내해 드리겠습니다.","JPN":"まずは安全な場所に移動しましょう。用意しておいたセーフハウスにご案内いたします。","ENG":"First we’ll escort you to a safe place. We have a safe house ready.","TWN":"我們有準備一個安全的地方，先移動到那裡吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럴 필요 없네. 나는 여기 있을 생각이거든.","JPN":"その必要はない。私はここに泊まるつもりだ。","ENG":"That won’t be necessary. I’m staying here.","TWN":"不需要，我待在這裡就好。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"죄송하지만, 이 마을은 침식체가 출몰했던 장소입니다.","JPN":"申し訳ありませんが、この村は侵食体が出没した地域です。","ENG":"But Master, C.O.s have been seen in this area.","TWN":"請恕我直言，這裡有侵蝕體出沒過。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"연고도 없는 마을 때문에 위험을 감수하실 이유가 있나요?","JPN":"ゆかりのない村のために、危険を甘受する理由がありますか？","ENG":"Why do you risk yourself for these strangers?","TWN":"有必要為了一個初來乍到的村莊而冒險嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이미 약속을 했기 때문이라네.","JPN":"約束をしたからだ。","ENG":"I made a promise.","TWN":"我已經答應人家咧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L43_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"구두로 맺은 계약은 법적인 효력이…….","JPN":"口頭で結んだ契約は法的効力が……","ENG":"But it was a verbal contract, and it’s not legally valid...","TWN":"口頭之約並沒有法律效力……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"나는 한 회사의 사장이고, 사업은 신뢰가 생명일세.","JPN":"私はコフィンカンパニーの社長、事業において信頼は命だ。","ENG":"I am the CEO of a company. Our business is based on trust.","TWN":"身為一家公司的老闆，誠信是經營事業的關鍵。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"한 번 깨진 신뢰는 돌이키기 매우 어려워. 이만하면 납득할 수 있겠나.","JPN":"一度崩れた信頼は取り返しがつかない。この理由なら納得してくれるかね。","ENG":"Once it’s broken, you’ll never get it back. Do you understand?","TWN":"信任一旦瓦解就很難再重建，這樣你懂嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"납득할 수는 없지만, 알겠습니다.","JPN":"納得はできませんが、承知しました。","ENG":"I don’t really understand it, but okay.","TWN":"不懂，但我會照主人的意思。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그것이 주인님의 뜻이라면, 메이드로서 전력을 다해 도와 드려야죠.","JPN":"それがご主人様の意思なら、メイドとして全力を尽くして助力いたします。","ENG":"If that’s what you wish, we will help you as your maids.","TWN":"既然主人的意思是這樣，那女僕自當竭盡全力協助您。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 고맙네. 다음에 그라운드 원에 오면 내가 식사나 한 번 대접하지.","JPN":"ははは。ありがとう。今度グラウンド・ワンに来たら、食事でもご馳走しよう。","ENG":"Hah hah, thank you. I’ll buy you dinner when you next visit Ground One.","TWN":"哈哈，謝啦！下次來 G1我請你吃飯啊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"자리를 비우신 동안 마을 분들과 다 함께 의논해 봤어요.","JPN":"不在の間、村のみんなと話し合いをしてみましたわ。","ENG":"We had a discussion while you were away.","TWN":"你們不在的時候，我有和村裡的人討論一下。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"침식체까지 나타나서 무섭기는 하지만, 저희는 역시 이 마을을 버릴 수 없나 봐요.","JPN":"侵食体まで現れて怖いのは事実ですが、私たちはやはりこの村を捨てるわけにはいきません。","ENG":"C.O.s are scary, but we don’t want to leave our home.","TWN":"雖然我們也很怕侵蝕體，但還是無法拋棄這個村子。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모처럼 활기찬 풍경을 기대했는데……. 이렇게 되어 버렸네요.","JPN":"活気に満ちた風景を期待しましたが……こうなってしまいましたね。","ENG":"We were all very hopeful... but I suppose that’s how it’s going to be.","TWN":"原本是期待看到滿滿的人……結果卻變成這樣。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"낙심하시기엔 아직 이릅니다. 사장님께서 맺으신 구두 계약은 아직 유효하니까요.","JPN":"落胆するにはまだ早いです。社長が結んだ口頭契約はまだ有効ですから。","ENG":"Don’t be so pessimistic. The verbal contract you had with our CEO is still valid.","TWN":"還不到放棄的時候，老闆的口頭之約還是有效的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그래도 정말 괜찮을까요?","JPN":"ですが、本当に大丈夫でしょうか？","ENG":"Do you really mean it?","TWN":"真的可以嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"이번 일에 관련없는 분들한테 너무 짐만 얹어 드리는 것 같아서…….","JPN":"村のことに関係のない方々に、あまりにも迷惑をかけている気がして……","ENG":"I feel bad, burdening you with our problem...","TWN":"明明就不關你們的事，卻給你們添不少麻煩………"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"물론 아무 이득 없이 나서는 건 아닙니다.","JPN":"もちろん何の利益も期待せず動くわけではありません。","ENG":"We are not doing this just for nothing.","TWN":"我們不做虧本生意的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"협력사인 플로라 메이드 서비스와의 관계도 중요한 변수니까요.","JPN":"協力会社のフローラメイドサービスとの関係も重要です。","ENG":"We are doing this to maintain our good relationship with the Flora Maid Service.","TWN":"與合作公司 芙蘿拉女僕服務公司的關係，也是重要的變數。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그러니 저희를 한 번 믿어 보시죠, 모네 어머니.","JPN":"ですので、私たちを一度信じてみてください、モネのお母様。","ENG":"So please have a faith in us, ma’am.","TWN":"莫妮的媽媽，就交給我們吧！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"코핀 컴퍼니는 결코 고객님께 실망을 안겨 드리지 않습니다.","JPN":"コフィンカンパニーは決してお客様を失望させません。","ENG":"We Coffin Company never let our clients down.","TWN":"科芬公司絕對會讓客人滿意的！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};